import './styles.css';
import Lenis from 'lenis';
import { createWorld } from './world';
import { createComposer } from './composer';
import { initHud } from './hud';
import { initBehaviors } from './behaviors';

/* ─── boot ───────────────────────────────────────────── */

const canvas = document.getElementById('gl') as HTMLCanvasElement;
const world = createWorld(canvas);
const { composer } = createComposer(world.renderer, world.scene, world.camera);

/* ─── Lenis smooth scroll ────────────────────────────── */

const lenis = new Lenis({
  lerp: 0.08,
  smoothWheel: true,
});

/* ─── pointer ────────────────────────────────────────── */

const pointer = { x: 0, y: 0 };
window.addEventListener('pointermove', (e) => {
  pointer.x = (e.clientX / window.innerWidth) * 2 - 1;
  pointer.y = (e.clientY / window.innerHeight) * 2 - 1;
}, { passive: true });

/* ─── scroll progress (0 → 1) ────────────────────────── */

function scrollProgress(): number {
  const h = document.documentElement.scrollHeight - window.innerHeight;
  return h > 0 ? Math.min(window.scrollY / h, 1) : 0;
}

/* ─── render loop ────────────────────────────────────── */

function loop(time: number) {
  lenis.raf(time);
  world.update(time, scrollProgress(), pointer);
  composer.render(time * 0.001);
  requestAnimationFrame(loop);
}
requestAnimationFrame(loop);

/* ─── resize ─────────────────────────────────────────── */

window.addEventListener('resize', () => {
  world.resize();
  composer.setSize(window.innerWidth, window.innerHeight);
}, { passive: true });

/* ─── HUD + interactive behaviors ────────────────────── */

initHud();
initBehaviors();
