import gsap from 'gsap';

export function initHud() {
  const label = document.querySelector<HTMLElement>('.scroll-label');
  const nav = document.querySelector<HTMLElement>('.hud-nav');

  // fade scroll label after first scroll
  let shown = true;
  const onScroll = () => {
    const y = window.scrollY || document.documentElement.scrollTop;
    if (y > 40 && shown && label) {
      shown = false;
      gsap.to(label, { opacity: 0, y: -10, duration: 0.6, ease: 'power2.out' });
    } else if (y <= 40 && !shown && label) {
      shown = true;
      gsap.to(label, { opacity: 1, y: 0, duration: 0.6, ease: 'power2.out' });
    }
  };
  window.addEventListener('scroll', onScroll, { passive: true });

  // subtle hover lift for nav
  if (nav) {
    nav.addEventListener('pointerenter', () => gsap.to(nav, { y: -2, duration: 0.3 }));
    nav.addEventListener('pointerleave', () => gsap.to(nav, { y: 0, duration: 0.3 }));
  }

  // gently reveal chapter text on entry
  const chapters = document.querySelectorAll<HTMLElement>('.chapter');
  const io = new IntersectionObserver((entries) => {
    for (const e of entries) {
      if (e.isIntersecting) {
        gsap.fromTo(
          e.target,
          { opacity: 0, y: 24 },
          { opacity: 1, y: 0, duration: 1.0, ease: 'power3.out' }
        );
        io.unobserve(e.target);
      }
    }
  }, { threshold: 0.2 });
  chapters.forEach((c) => {
    c.style.opacity = '0';
    io.observe(c);
  });
}
