import * as THREE from 'three';
import gsap from 'gsap';
import { theme } from './theme';

/* ── helpers ─────────────────────────────────────────────── */

function lemniscatePoint(t: number, scale = 1.8): THREE.Vector3 {
  const s = Math.sin(t);
  const c = Math.cos(t);
  const denom = 1 + s * s;
  return new THREE.Vector3(
    (scale * c) / denom,
    (scale * s * c) / denom,
    0
  );
}

/* ── iridescent torus material ──────────────────────────── */

function iridescentMaterial(): THREE.ShaderMaterial {
  return new THREE.ShaderMaterial({
    uniforms: {
      uTime: { value: 0 },
      uEmber: { value: theme.ember },
      uMagenta: { value: theme.magenta },
      uViolet: { value: theme.violet },
    },
    vertexShader: /* glsl */ `
      varying vec3 vNormal;
      varying vec3 vPosition;
      void main() {
        vNormal = normalize(normalMatrix * normal);
        vPosition = (modelViewMatrix * vec4(position, 1.0)).xyz;
        gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
      }
    `,
    fragmentShader: /* glsl */ `
      uniform float uTime;
      uniform vec3 uEmber;
      uniform vec3 uMagenta;
      uniform vec3 uViolet;
      varying vec3 vNormal;
      varying vec3 vPosition;
      void main() {
        vec3 viewDir = normalize(-vPosition);
        float fresnel = pow(1.0 - abs(dot(viewDir, vNormal)), 2.8);
        float t = fresnel + uTime * 0.15;
        vec3 col = mix(uEmber, uMagenta, smoothstep(0.0, 0.5, fract(t)));
        col = mix(col, uViolet, smoothstep(0.5, 1.0, fract(t)));
        col += fresnel * 0.35;
        gl_FragColor = vec4(col, 0.85);
      }
    `,
    transparent: true,
    side: THREE.DoubleSide,
  });
}

/* ── lemniscate ribbon ──────────────────────────────────── */

function createRibbon(): THREE.Mesh {
  const points: THREE.Vector3[] = [];
  const segments = 256;
  for (let i = 0; i <= segments; i++) {
    const t = (i / segments) * Math.PI * 2;
    points.push(lemniscatePoint(t, 1.8));
  }
  const curve = new THREE.CatmullRomCurve3(points, true);
  const tubeGeo = new THREE.TubeGeometry(curve, 256, 0.012, 8, true);
  const mat = new THREE.MeshBasicMaterial({
    color: theme.ember,
    transparent: true,
    opacity: 0.55,
  });
  return new THREE.Mesh(tubeGeo, mat);
}

/* ── particle field ─────────────────────────────────────── */

function createParticles(count = 1600): THREE.Points {
  const positions = new Float32Array(count * 3);
  const colors = new Float32Array(count * 3);
  const palette = [theme.ember, theme.magenta, theme.violet, theme.bone];

  for (let i = 0; i < count; i++) {
    positions[i * 3] = (Math.random() - 0.5) * 12;
    positions[i * 3 + 1] = (Math.random() - 0.5) * 12;
    positions[i * 3 + 2] = (Math.random() - 0.5) * 8;
    const c = palette[Math.floor(Math.random() * palette.length)];
    colors[i * 3] = c.r;
    colors[i * 3 + 1] = c.g;
    colors[i * 3 + 2] = c.b;
  }

  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  geo.setAttribute('color', new THREE.BufferAttribute(colors, 3));

  const mat = new THREE.PointsMaterial({
    size: 0.018,
    vertexColors: true,
    transparent: true,
    opacity: 0.7,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
  });

  return new THREE.Points(geo, mat);
}

/* ── fox mascot texture plane ───────────────────────────── */

function createFoxPlane(scene: THREE.Scene) {
  const loader = new THREE.TextureLoader();
  loader.load('/img/fox_mascot.png', (tex) => {
    tex.colorSpace = THREE.SRGBColorSpace;
    const mat = new THREE.MeshBasicMaterial({
      map: tex,
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
      opacity: 0.6,
    });
    const geo = new THREE.PlaneGeometry(0.7, 0.7);
    const mesh = new THREE.Mesh(geo, mat);
    mesh.position.set(0, 0, 0.01);
    scene.add(mesh);
  });
}

/* ── public API ──────────────────────────────────────────── */

export interface World {
  scene: THREE.Scene;
  camera: THREE.PerspectiveCamera;
  renderer: THREE.WebGLRenderer;
  torus: THREE.Mesh;
  ribbon: THREE.Mesh;
  particles: THREE.Points;
  torusMat: THREE.ShaderMaterial;
  update: (time: number, scroll: number, pointer: { x: number; y: number }) => void;
  resize: () => void;
}

export function createWorld(canvas: HTMLCanvasElement): World {
  /* renderer */
  const renderer = new THREE.WebGLRenderer({
    canvas,
    antialias: true,
    alpha: false,
  });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setSize(window.innerWidth, window.innerHeight);
  renderer.outputColorSpace = THREE.SRGBColorSpace;

  /* scene + camera */
  const scene = new THREE.Scene();
  scene.background = new THREE.Color(theme.obsidian);

  const camera = new THREE.PerspectiveCamera(
    45,
    window.innerWidth / window.innerHeight,
    0.1,
    100
  );
  camera.position.set(0, 0, 6.2);

  /* objects */
  const torusMat = iridescentMaterial();
  const torusGeo = new THREE.TorusGeometry(1.1, 0.18, 64, 128);
  const torus = new THREE.Mesh(torusGeo, torusMat);
  scene.add(torus);

  const ribbon = createRibbon();
  scene.add(ribbon);

  const particles = createParticles(1600);
  scene.add(particles);

  /* fox texture inside ring (fire-and-forget) */
  createFoxPlane(scene);

  /* lights (subtle fill for the torus shader isn't using them, but keep for any added objects) */
  const ambient = new THREE.AmbientLight(0xffffff, 0.3);
  scene.add(ambient);

  /* update fn */
  function update(time: number, scroll: number, pointer: { x: number; y: number }) {
    const t = time * 0.001;

    // torus rotation
    torus.rotation.x = t * 0.12 + pointer.y * 0.08;
    torus.rotation.y = t * 0.18 + pointer.x * 0.08;
    torusMat.uniforms.uTime.value = t;

    // ribbon drifts
    ribbon.rotation.z = t * 0.05;
    ribbon.position.y = scroll * 0.3;

    // camera dolly on scroll (z 6.2 → 3.4)
    camera.position.z = 6.2 - scroll * 2.8;

    // pointer parallax
    camera.position.x = pointer.x * 0.15;
    camera.position.y = pointer.y * 0.15;

    // subtle particle drift
    particles.rotation.y = t * 0.02;
    particles.rotation.x = t * 0.01;
  }

  function resize() {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(window.innerWidth, window.innerHeight);
  }

  return { scene, camera, renderer, torus, ribbon, particles, torusMat, update, resize };
}
