import gsap from 'gsap';

/* ─── XP / Leveling ────────────────────────────────────── */

const LEVELS = [
  { name: 'Rookie', threshold: 0 },
  { name: 'Apprentice', threshold: 500 },
  { name: 'Builder', threshold: 1500 },
  { name: 'Architect', threshold: 3000 },
  { name: 'Operator', threshold: 5000 },
  { name: 'God Tier', threshold: 8000 },
];

function getLevel(xp: number) {
  let lvl = LEVELS[0];
  for (const l of LEVELS) if (xp >= l.threshold) lvl = l;
  return lvl;
}

function loadXP(): number {
  try { return parseInt(localStorage.getItem('ccs-xp') || '0', 10); } catch { return 0; }
}

function saveXP(xp: number) {
  try { localStorage.setItem('ccs-xp', String(xp)); } catch { /* noop */ }
}

function loadCompleted(): Set<string> {
  try { return new Set(JSON.parse(localStorage.getItem('ccs-completed') || '[]')); } catch { return new Set(); }
}

function saveCompleted(set: Set<string>) {
  try { localStorage.setItem('ccs-completed', JSON.stringify([...set])); } catch { /* noop */ }
}

function updateXPDisplay(xp: number) {
  const lvl = getLevel(xp);
  const idx = LEVELS.indexOf(lvl);
  const next = idx < LEVELS.length - 1 ? LEVELS[idx + 1] : lvl;
  const cur = document.querySelector<HTMLElement>('.xp-cur');
  const nxt = document.querySelector<HTMLElement>('.xp-next');
  const bar = document.querySelector<HTMLElement>('.xp-bar-inner');
  const name = document.querySelector<HTMLElement>('.level-name');

  if (cur) cur.textContent = String(xp);
  if (nxt) nxt.textContent = String(next.threshold);
  if (name) name.textContent = lvl.name;

  if (bar) {
    const pct = next.threshold > lvl.threshold
      ? ((xp - lvl.threshold) / (next.threshold - lvl.threshold)) * 100
      : 100;
    bar.style.width = `${Math.min(pct, 100)}%`;
  }

  // badge highlighting
  document.querySelectorAll<HTMLElement>('.achievement').forEach((el) => {
    const t = parseInt(el.dataset.threshold || '0', 10);
    el.classList.toggle('unlocked', xp >= t);
  });
}

function showToast(msg: string) {
  const toast = document.getElementById('toast');
  if (!toast) return;
  toast.textContent = msg;
  toast.classList.add('show');
  setTimeout(() => toast.classList.remove('show'), 2400);
}

function initXP() {
  let xp = loadXP();
  const completed = loadCompleted();
  updateXPDisplay(xp);

  // restore completed state
  completed.forEach((id) => {
    const btn = document.querySelector<HTMLButtonElement>(`[data-complete-id="${id}"]`);
    if (btn) { btn.disabled = true; btn.textContent = 'Completed'; }
  });

  document.querySelectorAll<HTMLButtonElement>('.complete-btn').forEach((btn) => {
    btn.addEventListener('click', () => {
      const id = btn.dataset.completeId || '';
      const pts = parseInt(btn.dataset.completeXp || '0', 10);
      if (completed.has(id)) return;
      completed.add(id);
      saveCompleted(completed);
      xp += pts;
      saveXP(xp);
      updateXPDisplay(xp);
      btn.disabled = true;
      btn.textContent = 'Completed';
      showToast(`+${pts} XP`);
    });
  });
}

/* ─── Copy Buttons ──────────────────────────────────────── */

function initCopy() {
  document.querySelectorAll<HTMLButtonElement>('.copy-btn').forEach((btn) => {
    btn.addEventListener('click', () => {
      const text = btn.dataset.copy || '';
      navigator.clipboard.writeText(text).then(() => {
        const prev = btn.textContent;
        btn.textContent = 'Copied!';
        setTimeout(() => { btn.textContent = prev; }, 1600);
      });
    });
  });
}

/* ─── Skill Card Toggle ────────────────────────────────── */

function initSkillCards() {
  document.querySelectorAll<HTMLElement>('.skill-card').forEach((card) => {
    const top = card.querySelector<HTMLElement>('.skill-top');
    const nameEl = card.querySelector<HTMLElement>('.skill-name');
    const descEl = card.querySelector<HTMLElement>('.skill-desc');

    const togglers = [top, nameEl, descEl].filter(Boolean) as HTMLElement[];

    togglers.forEach((el) => {
      el.style.cursor = 'pointer';
      el.addEventListener('click', () => {
        const isOpen = card.classList.contains('open');
        // close all others
        document.querySelectorAll('.skill-card.open').forEach((c) => c.classList.remove('open'));
        if (!isOpen) card.classList.add('open');
      });
    });
  });
}

/* ─── Audio Players ─────────────────────────────────────── */

function initAudio() {
  document.querySelectorAll<HTMLButtonElement>('.audio-btn').forEach((btn) => {
    btn.addEventListener('click', () => {
      const mod = btn.dataset.audio || '';
      const player = document.getElementById(`player-${mod}`);
      const audio = player?.querySelector<HTMLAudioElement>('audio');
      if (!audio) return;

      if (audio.paused) {
        // pause all others
        document.querySelectorAll<HTMLAudioElement>('audio').forEach((a) => { if (a !== audio) a.pause(); });
        audio.play();
        btn.textContent = '⏸';
      } else {
        audio.pause();
        btn.textContent = '▶';
      }
    });
  });

  // progress + time
  document.querySelectorAll<HTMLAudioElement>('audio').forEach((audio) => {
    const mod = audio.dataset.audio || '';
    const player = document.getElementById(`player-${mod}`);
    if (!player) return;

    const bar = player.querySelector<HTMLElement>('.audio-progress-bar');
    const curEl = player.querySelector<HTMLElement>('.audio-cur');
    const durEl = player.querySelector<HTMLElement>('.audio-dur');

    const fmt = (s: number) => {
      const m = Math.floor(s / 60);
      const sec = Math.floor(s % 60);
      return `${m}:${sec.toString().padStart(2, '0')}`;
    };

    audio.addEventListener('loadedmetadata', () => { if (durEl) durEl.textContent = fmt(audio.duration); });
    audio.addEventListener('timeupdate', () => {
      if (bar && audio.duration) bar.style.width = `${(audio.currentTime / audio.duration) * 100}%`;
      if (curEl) curEl.textContent = fmt(audio.currentTime);
    });
    audio.addEventListener('ended', () => {
      const btn = document.querySelector<HTMLButtonElement>(`[data-audio="${mod}"].audio-btn`);
      if (btn) btn.textContent = '▶';
    });
  });

  // seek
  document.querySelectorAll<HTMLElement>('.audio-progress-container').forEach((container) => {
    const mod = container.dataset.seek || '';
    const audio = document.querySelector<HTMLAudioElement>(`audio[data-audio="${mod}"]`);
    if (!audio) return;
    container.addEventListener('click', (e) => {
      const rect = container.getBoundingClientRect();
      const pct = (e.clientX - rect.left) / rect.width;
      if (audio.duration) audio.currentTime = pct * audio.duration;
    });
  });

  // speed
  document.querySelectorAll<HTMLButtonElement>('.audio-speed-btn').forEach((btn) => {
    btn.addEventListener('click', () => {
      const mod = btn.dataset.audio || '';
      const audio = document.querySelector<HTMLAudioElement>(`audio[data-audio="${mod}"]`);
      if (!audio) return;
      const speed = parseFloat(btn.dataset.speed || '1');
      audio.playbackRate = speed;
      // highlight
      btn.closest('.audio-controls')?.querySelectorAll('.audio-speed-btn').forEach((b) => b.classList.remove('active'));
      btn.classList.add('active');
    });
  });
}

/* ─── Carousels ─────────────────────────────────────────── */

function initCarousels() {
  document.querySelectorAll<HTMLButtonElement>('[data-carousel-prev]').forEach((btn) => {
    btn.addEventListener('click', () => navigate(btn.dataset.carouselPrev || '', -1));
  });
  document.querySelectorAll<HTMLButtonElement>('[data-carousel-next]').forEach((btn) => {
    btn.addEventListener('click', () => navigate(btn.dataset.carouselNext || '', 1));
  });

  function navigate(id: string, dir: number) {
    const track = document.getElementById(`carousel-${id}`);
    if (!track) return;
    const slides = track.querySelectorAll<HTMLElement>('.carousel-slide');
    let cur = 0;
    slides.forEach((s, i) => { if (s.classList.contains('active')) cur = i; });
    slides[cur].classList.remove('active');
    cur = (cur + dir + slides.length) % slides.length;
    slides[cur].classList.add('active');

    // dots
    const nav = track.closest('.story-carousel')?.querySelector('.carousel-dots');
    if (nav) {
      nav.querySelectorAll('.carousel-dot').forEach((d, i) => d.classList.toggle('active', i === cur));
    }
  }
}

/* ─── Rain dots in nav ──────────────────────────────────── */

function initRain() {
  const container = document.querySelector<HTMLElement>('.rain');
  if (!container) return;

  function drop() {
    const dot = document.createElement('span');
    dot.className = 'rain-dot';
    dot.style.left = `${Math.random() * 100}%`;
    dot.style.animationDuration = `${1.2 + Math.random() * 1.5}s`;
    container!.appendChild(dot);
    dot.addEventListener('animationend', () => dot.remove());
  }

  setInterval(drop, 400);
}

/* ─── public ────────────────────────────────────────────── */

export function initBehaviors() {
  initXP();
  initCopy();
  initSkillCards();
  initAudio();
  initCarousels();
  initRain();
}
