import {
  EffectComposer,
  RenderPass,
  EffectPass,
  BloomEffect,
  ChromaticAberrationEffect,
  NoiseEffect,
  VignetteEffect,
  KernelSize,
  BlendFunction
} from 'postprocessing';
import { Vector2, WebGLRenderer, Scene, Camera } from 'three';

export function createComposer(renderer: WebGLRenderer, scene: Scene, camera: Camera) {
  const composer = new EffectComposer(renderer, { frameBufferType: undefined });
  composer.addPass(new RenderPass(scene, camera));

  const bloom = new BloomEffect({
    intensity: 0.7,
    luminanceThreshold: 0.32,
    luminanceSmoothing: 0.5,
    mipmapBlur: true,
    kernelSize: KernelSize.LARGE
  });

  const chroma = new ChromaticAberrationEffect({
    offset: new Vector2(0.0008, 0.0012),
    radialModulation: true,
    modulationOffset: 0.2
  });

  const noise = new NoiseEffect({ premultiply: true, blendFunction: BlendFunction.SOFT_LIGHT });
  (noise.blendMode as any).opacity.value = 0.22;

  const vignette = new VignetteEffect({ offset: 0.25, darkness: 0.9 });

  composer.addPass(new EffectPass(camera, bloom, chroma, noise, vignette));
  return { composer, bloom, chroma, noise, vignette };
}
